import fs from 'fs';
import path from 'path';

// ===== CONFIG =====
const GITHUB_USER = 'yoshikun';
const GITHUB_REPO = 'OpenClaw';
const COOKIE_FILE = 'C:/Users/yyzypublic/.openclaw/workspace/github_cookies.json';
const BACKUP_ROOT = 'C:/Users/yyzypublic/.openclaw';

// Files/Dirs to backup (relative to BACKUP_ROOT)
const BACKUP_ITEMS = [
  // Workspace files
  'workspace/AGENTS.md',
  'workspace/SOUL.md',
  'workspace/USER.md',
  'workspace/IDENTITY.md',
  'workspace/TOOLS.md',
  'workspace/HEARTBEAT.md',
  'workspace/MEMORY.md',  // may not exist

  // Config
  'openclaw.json',

  // Plugin skills
  'plugin-skills/',

  // Agent config
  'agents/',
];

// Files to EXCLUDE (secrets, runtime data)
const EXCLUDE_PATTERNS = [
  /cookies\.json$/,
  /csrf\.json$/,
  /tapd_/,
  /node_modules/,
  /package-lock\.json/,
  /\.sessions/,
  /subagents/,
  /logs/,
  /cron/,
  /delivery-queue/,
  /\.git/,
  /exec-approvals\.json/,
  /gateway-restart-intent\.json/,
  /rejected\./,
  /\.bak/,
  /\.last-good/,
];

// ===== HELPERS =====
function shouldExclude(name) {
  return EXCLUDE_PATTERNS.some(p => p.test(name));
}

function walkDir(dir, baseDir) {
  const results = [];
  try {
    const list = fs.readdirSync(dir, { withFileTypes: true });
    for (const item of list) {
      const fullPath = path.join(dir, item.name);
      const relPath = path.relative(baseDir, fullPath);
      if (shouldExclude(relPath) || shouldExclude(item.name)) continue;
      if (item.isDirectory()) {
        results.push(...walkDir(fullPath, baseDir));
      } else {
        results.push(relPath);
      }
    }
  } catch (e) {
    if (e.code !== 'ENOENT') console.error('  Warning:', e.message);
  }
  return results;
}

async function getExistingSha(api, filePath) {
  const r = await fetch(`https://api.github.com/repos/${GITHUB_USER}/${GITHUB_REPO}/contents/${filePath}`, { headers: api.headers });
  if (r.status === 404) return null;
  if (!r.ok) return null;
  const data = await r.json();
  return data.sha;
}

async function uploadFile(api, filePath, content, sha = null) {
  const body = {
    message: `Backup: ${filePath}`,
    content: Buffer.from(content, 'utf8').toString('base64'),
    branch: 'master',
  };
  if (sha) body.sha = sha;

  const r = await fetch(`https://api.github.com/repos/${GITHUB_USER}/${GITHUB_REPO}/contents/${filePath}`, {
    method: 'PUT',
    headers: api.jsonHeaders,
    body: JSON.stringify(body),
  });
  if (!r.ok) {
    const err = await r.text();
    console.error(`  ❌ ${filePath}: ${r.status} - ${err.substring(0,100)}`);
    return false;
  }
  console.log(`  ✅ ${filePath}`);
  return true;
}

