  const cookies = JSON.parse(fs.readFileSync(COOKIE_FILE, 'utf8'));
  const cookieStr = cookies.map(c => `${c.name}=${c.value}`).join('; ');
  const api = {
    headers: { Cookie: cookieStr, Accept: 'application/json', 'User-Agent': 'OpenClaw' },
    jsonHeaders: { Cookie: cookieStr, Accept: 'application/json', 'User-Agent': 'OpenClaw', 'Content-Type': 'application/json' },
  };

  // Verify auth
  const userRes = await fetch('https://api.github.com/user', { headers: api.headers });
  const user = await userRes.json();
  if (!user.login) {
    console.error('Auth failed - cookies may be expired. Run github auth again.');
    process.exit(1);
  }
  console.log(`Authenticated as: ${user.login}`);

  // Check repo
  const repoRes = await fetch(`https://api.github.com/repos/${GITHUB_USER}/${GITHUB_REPO}`, { headers: api.headers });
  if (!repoRes.ok) {
    console.error(`Repo ${GITHUB_USER}/${GITHUB_REPO} not found!`);
    process.exit(1);
  }
  console.log(`Repo: ${GITHUB_USER}/${GITHUB_REPO}\n`);

  // Collect files
  const allFiles = [];
  for (const item of BACKUP_ITEMS) {
    const fullPath = path.join(BACKUP_ROOT, item);
    if (!fs.existsSync(fullPath)) {
      console.log(`  Skipping (not found): ${item}`);
      continue;
    }
    if (fs.statSync(fullPath).isDirectory()) {
      allFiles.push(...walkDir(fullPath, BACKUP_ROOT));
    } else {
      const relPath = item.replace(/\\/g, '/');
      if (!shouldExclude(relPath)) allFiles.push(relPath);
    }
  }

  console.log(`Found ${allFiles.length} files to backup:\n`);
  allFiles.sort();

  // Upload each file
  let success = 0;
  let fail = 0;
  for (const filePath of allFiles) {
    const fullPath = path.join(BACKUP_ROOT, filePath.replace(/\//g, path.sep));
    try {
      const content = fs.readFileSync(fullPath, 'utf8');
      const apiPath = filePath.replace(/\\/g, '/');
      const existingSha = await getExistingSha(api, apiPath);
      const ok = await uploadFile(api, apiPath, content, existingSha);
      if (ok) success++; else fail++;
    } catch (e) {
      console.error(`  ❌ ${filePath}: ${e.message}`);
      fail++;
    }
  }

  console.log(`\n=== Done! ${success} uploaded, ${fail} failed ===`);
}

